const body = $json.body ?? $json;

const rawText = String(body.message ?? body.raw_text ?? '').trim();
if (!rawText) {
  throw new Error('Missing message/raw_text in webhook payload');
}

const chatId = body.chat_id == null || body.chat_id === '' ? null : Number(body.chat_id);
if (chatId !== null && !Number.isFinite(chatId)) {
  throw new Error('chat_id must be numeric when provided');
}

return [{
  json: {
    source: String(body.source ?? 'telegram_userbot'),
    message_id: body.message_id == null ? null : Number(body.message_id),
    sender_id: body.sender_id == null ? null : Number(body.sender_id),
    chat_id: chatId,
    chat_title: body.chat_title ?? null,
    inbound_date: body.date ?? new Date().toISOString(),
    timezone: $env.GENERIC_TIMEZONE || 'Asia/Kuala_Lumpur',
    raw_text: rawText
  }
}];

const payload = $json;
const now = new Date().toISOString();

const systemPrompt = [
  'You are Veloce extraction engine.',
  'Return ONLY valid JSON with this exact shape:',
  '{"tasks":[{"task_name":"string","deadline_iso":"ISO-8601 string","estimated_duration_minutes":90,"confidence":0.0,"needs_clarification":false,"clarification_question":null}]}',
  'Rules:',
  '1) Extract academic/professional tasks and deadlines.',
  '2) If no actionable task, return {"tasks":[]}.',
  '3) deadline_iso must be timezone-aware ISO-8601.',
  '4) estimated_duration_minutes must be integer >= 15.',
  '5) If uncertain, still output best estimate and set needs_clarification=true.'
].join('\n');

const userPrompt = [
  `Current time: ${now}`,
  `Timezone: ${payload.timezone}`,
  'Input text:',
  payload.raw_text
].join('\n');

const agentPrompt = [
  systemPrompt,
  '',
  userPrompt
].join('\n');

return [{
  json: {
    ...payload,
    glm_request: {
      model: $env.ZAI_MODEL || 'glm-4.5',
      temperature: 0.1,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    },
    agent_prompt: agentPrompt
  }
}];

const source = $('Normalize Inbound').item.json;
const modelResponse = $json;

let content =
  modelResponse?.output ??
  modelResponse?.text ??
  modelResponse?.response?.text ??
  modelResponse?.response ??
  modelResponse?.data?.output ??
  modelResponse?.choices?.[0]?.message?.content;

let parsed;

if (content != null && typeof content === 'object' && !Array.isArray(content)) {
  parsed = content;
} else {
  if (Array.isArray(content)) {
    content = content
      .map((part) => (typeof part === 'string' ? part : JSON.stringify(part)))
      .join('\n');
  }

  if (content == null) {
    throw new Error('AI Agent response missing output/text/response content');
  }

  if (typeof content !== 'string') {
    content = JSON.stringify(content);
  }

  const cleaned = content
    .replace(/^```json\s*/i, '')
    .replace(/^```/i, '')
    .replace(/```$/, '')
    .trim();

  try {
    parsed = JSON.parse(cleaned);
  } catch (err) {
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (!jsonMatch) {
      throw new Error(`AI Agent output is not valid JSON: ${cleaned}`);
    }
    parsed = JSON.parse(jsonMatch[0]);
  }
}

const rawTasks = Array.isArray(parsed?.tasks) ? parsed.tasks : [];
const tasks = rawTasks
  .map((t) => ({
    task_name: String(t.task_name ?? '').trim(),
    deadline_iso: String(t.deadline_iso ?? '').trim(),
    estimated_duration_minutes: Math.max(15, Math.floor(Number(t.estimated_duration_minutes ?? 90) || 90)),
    confidence: Number(t.confidence ?? 0.5),
    needs_clarification: Boolean(t.needs_clarification),
    clarification_question: t.clarification_question ?? null
  }))
  .filter((t) => t.task_name && t.deadline_iso);

const selectedTask = tasks.length ? tasks.sort((a, b) => Date.parse(a.deadline_iso) - Date.parse(b.deadline_iso))[0] : null;

return [{
  json: {
    ...source,
    glm_raw: parsed,
    extracted_tasks: tasks,
    selected_task: selectedTask
  }
}];

const task = $json.selected_task;
if (!task) throw new Error('selected_task missing');

const timeMin = new Date();
const timeMax = new Date(task.deadline_iso);
if (Number.isNaN(timeMax.getTime())) {
  throw new Error(`Invalid deadline_iso: ${task.deadline_iso}`);
}
if (timeMax <= timeMin) {
  throw new Error('deadline_iso is in the past; cannot schedule automatically');
}

return [{
  json: {
    ...$json,
    calendar_time_min: timeMin.toISOString(),
    calendar_time_max: timeMax.toISOString()
  }
}];

const prior = $('Prepare Calendar Window').item.json;
const response = $json;

const eventCandidates = Array.isArray(response.items)
  ? response.items
  : Array.isArray(response.events)
    ? response.events
    : Array.isArray(response.data?.items)
      ? response.data.items
      : [];

const busyCandidates = Array.isArray(response.busy)
  ? response.busy
  : Array.isArray(response.calendars?.primary?.busy)
    ? response.calendars.primary.busy
    : [];

const durationMs = Number(prior.selected_task.estimated_duration_minutes) * 60000;
const deadline = new Date(prior.calendar_time_max);
let cursor = new Date(prior.calendar_time_min);

const busyFromEvents = eventCandidates
  .map((e) => {
    const startRaw = e?.start?.dateTime || e?.start || (e?.start?.date ? `${e.start.date}T00:00:00` : null);
    const endRaw = e?.end?.dateTime || e?.end || (e?.end?.date ? `${e.end.date}T00:00:00` : null);
    const start = startRaw ? new Date(startRaw) : null;
    const end = endRaw ? new Date(endRaw) : null;
    if (!start || !end || Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null;
    return { start, end, summary: e.summary ?? 'Busy' };
  })
  .filter(Boolean);

const busyFromBusySlots = busyCandidates
  .map((slot) => {
    const startRaw = slot?.start ?? null;
    const endRaw = slot?.end ?? null;
    const start = startRaw ? new Date(startRaw) : null;
    const end = endRaw ? new Date(endRaw) : null;
    if (!start || !end || Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null;
    return { start, end, summary: 'Busy' };
  })
  .filter(Boolean);

const busy = [...busyFromEvents, ...busyFromBusySlots]
  .sort((a, b) => a.start.getTime() - b.start.getTime());

let chosenStart = null;
let chosenEnd = null;

for (const slot of busy) {
  if (slot.end <= cursor) continue;
  if (slot.start > cursor && (slot.start.getTime() - cursor.getTime()) >= durationMs) {
    chosenStart = new Date(cursor);
    chosenEnd = new Date(cursor.getTime() + durationMs);
    break;
  }
  if (slot.end > cursor) {
    cursor = new Date(slot.end);
  }
}

if (!chosenStart) {
  if ((deadline.getTime() - cursor.getTime()) >= durationMs) {
    chosenStart = new Date(cursor);
    chosenEnd = new Date(cursor.getTime() + durationMs);
  }
}

if (!chosenStart || !chosenEnd || chosenEnd > deadline) {
  return [{
    json: {
      ...prior,
      slot_found: false,
      slot_reason: 'No free slot before deadline'
    }
  }];
}

return [{
  json: {
    ...prior,
    slot_found: true,
    proposed_start: chosenStart.toISOString(),
    proposed_end: chosenEnd.toISOString()
  }
}];

const scheduling = $('Find Free Slot').item.json;
const event = $json;

const startText = scheduling.proposed_start;
const endText = scheduling.proposed_end;

const textLines = [
  'Veloce scheduled your task successfully.',
  `Task: ${scheduling.selected_task.task_name}`,
  `When: ${startText} to ${endText}`,
  event.htmlLink ? `Calendar: ${event.htmlLink}` : null
].filter(Boolean);

return [{
  json: {
    ...scheduling,
    created_event: event,
    telegram_message: textLines.join('\n')
  }
}];
